INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.11.78','cb','cb.adi.11','ЧБ Ади 11.78',78,'যেইমাত্র শুনিলেন মুকুন্দের গীতে ।
পড়িলা ঈশ্বরপুরী ঢলি’ পৃথিবীতে ॥৭৮॥','йеи-ма̄тра ш́унилена мукундера гӣте
пад̣ила̄ ӣш́вара-пурӣ д̣хали’ пр̣тхивӣте',NULL,NULL),('cb.adi.11.79','cb','cb.adi.11','ЧБ Ади 11.79',79,'নয়নের জলে অন্ত নাহিক তাহান ।
পুনঃ পুনঃ বাড়ে প্রেম-ধারার পয়ান ॥৭৯॥','найанера джале анта на̄хика та̄ха̄на
пунах̣-пунах̣ ба̄д̣е према-дха̄ра̄ра пайа̄на',NULL,NULL),('cb.adi.11.80','cb','cb.adi.11','ЧБ Ади 11.80',80,'আস্তে-ব্যস্তে অদ্বৈত তুলিলা নিজ-কোলে ।
সিঞ্চিত হইল অঙ্গ নয়নের জলে ॥৮০॥','а̄сте вйасте адваита тулила̄ ниджа-коле
син̃чита хаила ан̇га найанера джале',NULL,NULL),('cb.adi.11.81','cb','cb.adi.11','ЧБ Ади 11.81',81,'সম্বরণ নহে প্রেম পুনঃ পুনঃ বাড়ে ।
সন্তোষে মুকুন্দ উচ্চ করি’ শ্লোক পড়ে ॥৮১॥','самваран̣а нахе према пунах̣-пунах̣ ба̄д̣е
сантош̣е мукунда учча кари’ ш́лока пад̣е',NULL,NULL),('cb.adi.11.82','cb','cb.adi.11','ЧБ Ади 11.82',82,'দেখিয়া বৈষ্ণব সব প্রেমের বিকার ।
অতুল আনন্দ মনে জন্মিল সবার ॥৮২॥','декхийа̄ ваиш̣н̣ава саба премера вика̄ра
атула а̄нанда мане джанмила саба̄ра',NULL,NULL),('cb.adi.11.83','cb','cb.adi.11','ЧБ Ади 11.83',83,'পাছে সবে চিনিলেন শ্রীঈশ্বরপুরী ।
প্রেম দেখি’ সবেই সঙরে ‘হরি-হরি’॥৮৩॥','па̄чхе сабе чинилена ш́рӣ-ӣш́вара-пурӣ
према декхи сабеи сан̇аре ‘хари-хари’',NULL,NULL),('cb.adi.11.84','cb','cb.adi.11','ЧБ Ади 11.84',84,'এইমত ঈশ্বরপুরী নবদ্বীপপুরে ।
অলক্ষিতে বুলেন, চিনিতে কেহ নারে ॥৮৪॥
দৈবে একদিন প্রভু শ্রীগৌরসুন্দর ।
পড়াইয়া আইসেন আপনার ঘর ॥৮৫॥
পথে দেখা হইল ঈশ্বরপুরী-সনে ।
ভৃত্য দেখি’ প্রভু নমস্করিলা আপনে ॥৮৬॥','эи-мате ӣш́вара-пурӣ навадвӣпа-пурӣ
алакш̣ите булена, чините кеха на̄ре
даиве эка-дина прабху ш́рӣ-гаурасундара
пад̣а̄ийа̄ а̄исена а̄пана̄ра гхара
патхе декха̄ хаила ӣш́вара-пурӣ-сане
бхр̣тйа декхи’ прабху намаскарила̄ а̄пане',NULL,NULL),('cb.adi.11.87','cb','cb.adi.11','ЧБ Ади 11.87',87,'অতি অনির্ব্বচনীয় ঠাকুর সুন্দর ।
সর্ব্বমতে সর্ব্ব-বিলক্ষণ-গুণধর ॥৮৭॥','ати анирвачанӣйа т̣ха̄кура сундара
сарва-мате сарва-вилакш̣ан̣а-гун̣а-дхара',NULL,NULL),('cb.adi.11.88','cb','cb.adi.11','ЧБ Ади 11.88',88,'যদ্যপি তাহান মর্ম্ম কেহ নাহি জানে ।
তথাপি সাধ্বস করে দেখি’ সর্ব্বজনে ॥৮৮॥','йадйапи та̄ха̄на марма кеха на̄хи джа̄не
татха̄пи са̄дхаваса каре декхи’ сарва-джане',NULL,NULL),('cb.adi.11.89','cb','cb.adi.11','ЧБ Ади 11.89',89,'চাহেন ঈশ্বরপুরী প্রভুর শরীর ।
সিদ্ধপুরুষের প্রায় পরম-গম্ভীর ॥৮৯॥','ча̄хена ӣш́вара-пурӣ прабхура ш́арӣра
сиддха-пуруш̣ера пра̄йа парама гамбхӣра',NULL,NULL),('cb.adi.11.90','cb','cb.adi.11','ЧБ Ади 11.90',90,'জিজ্ঞাসেন,—“তোমার কি নাম, বিপ্রবর ? ।
কি পুঁথি পড়াও, পড়, কোন্ স্থানে ঘর ?” ॥৯০॥','джиджн̃а̄сена, — ‘тома̄ра ки на̄ма, випра-вара?
ки пун̇тхи пад̣а̄о, пад̣а, кон стха̄не гхара?’',NULL,NULL),('cb.adi.11.91','cb','cb.adi.11','ЧБ Ади 11.91',91,'শেষে সভে বলিলেন,—“নিমাই-পণ্ডিত” ।
“তুমি সে !” বলিয়া বড় হৈলা হরষিত ॥৯১॥','ш́еш̣е сабе болилена, — ‘нима̄и пан̣д̣ита’
‘туми се!’ балийа̄ бад̣а хаила̄ хараш̣ита',NULL,NULL),('cb.adi.11.92','cb','cb.adi.11','ЧБ Ади 11.92',92,'ভিক্ষা-নিমন্ত্রণ প্রভু করিলেন তানে ।
মহাদরে গৃহে লই’ চলিলা আপনে ॥৯২॥','бхикш̣а̄-нимантран̣а прабху карилена та̄’не
маха̄даре гр̣хе лаи’ чалила̄ а̄пане',NULL,NULL),('cb.adi.11.93','cb','cb.adi.11','ЧБ Ади 11.93',93,'কৃষ্ণের নৈবেদ্য শচী করিলেন গিয়া ।
ভিক্ষা করি’ বিষ্ণু-গৃহে বসিলা আসিয়া ॥৯৩॥','кр̣ш̣н̣ера наиведйа ш́ачӣ карилена гийа̄
бхикш̣а̄ кари’ виш̣н̣у-гр̣хе васила̄ а̄сийа̄',NULL,NULL),('cb.adi.11.94','cb','cb.adi.11','ЧБ Ади 11.94',94,'কৃষ্ণের প্রস্তাব সব কহিতে লাগিলা ।
কহিতে কৃষ্ণের কথা অবশ হইলা ॥৯৪॥','кр̣ш̣н̣ера праста̄ва саба кахите ла̄гила̄
кахите кр̣ш̣н̣ера катха̄ аваш́а хаила̄',NULL,NULL),('cb.adi.11.95','cb','cb.adi.11','ЧБ Ади 11.95',95,'অপূর্ব্ব প্রেমের ধারা দেখিয়া সন্তোষ ।
না প্রকাশে’ আপনা’ লোকের দীন-দোষ ॥৯৫॥','апӯрва премера дха̄ра̄ декхийа̄ сантош̣а
на̄ прака̄ш́е’ а̄пана’ локера дӣна-дош̣а',NULL,NULL),('cb.adi.11.96','cb','cb.adi.11','ЧБ Ади 11.96',96,'মাস-কত গোপীনাথ-আচার্য্যের ঘরে ।
রহিলা ঈশ্বরপুরী নবদ্বীপপুরে ॥৯৬॥','ма̄са-ката гопӣна̄тха а̄ча̄рйера гхаре
рахила̄ ӣш́вара-пурӣ навадвӣпа-пурӣ',NULL,NULL),('cb.adi.11.97','cb','cb.adi.11','ЧБ Ади 11.97',97,'সবে বড় উল্লসিত দেখিতে তাহানে ।
প্রভুও দেখিতে নিত্য চলেন আপনে ॥৯৭॥','сабе бад̣а улласита декхите та̄ха̄не
прабху о декхите нитйа чалена а̄пане',NULL,NULL),('cb.adi.11.98','cb','cb.adi.11','ЧБ Ади 11.98',98,'গদাধর-পণ্ডিতের দেখি’ প্রেমজল ।
বড় প্রীত বাসে’ তানে বৈষ্ণবসকল ॥৯৮॥','гада̄дхара пан̣д̣итера декхи’ према-джала
бад̣а прӣта ва̄се’ та̄’не ваиш̣н̣ава-сакале',NULL,NULL),('cb.adi.11.99','cb','cb.adi.11','ЧБ Ади 11.99',99,'শিশু হৈতে সংসারে বিরক্ত বড় মনে ।
ঈশ্বরপুরীও স্নেহ করেন তাহানে ॥৯৯॥','ш́иш́у хаите сам̇са̄ре виракта бад̣а мане
ӣш́вара-пурӣ о снеха карена та̄ха̄не',NULL,NULL),('cb.adi.11.100','cb','cb.adi.11','ЧБ Ади 11.100',100,'গদাধর-পণ্ডিতেরে আপনার কৃত ।
পুঁথি পড়ায়েন নাম ‘কৃষ্ণলীলামৃত’ ॥১০০॥','гада̄дхара-пан̣д̣итере а̄пана̄ра кр̣та
пун̇тхи пад̣а̄йена на̄ма ‘кр̣ш̣н̣а-лӣла̄мр̣та’',NULL,NULL),('cb.adi.11.101','cb','cb.adi.11','ЧБ Ади 11.101',101,'পড়াইয়া পড়িয়া ঠাকুর সন্ধ্যাকালে ।
ঈশ্বরপুরীরে নমস্কারিবারে চলে ॥১০১॥','пад̣а̄ийа̄ пад̣айа̄ т̣ха̄кура сандхйа̄-ка̄ле
ӣш́вара-пурӣре намаскариба̄ре чале',NULL,NULL),('cb.adi.11.102','cb','cb.adi.11','ЧБ Ади 11.102',102,'প্রভু দেখি’ শ্রীঈশ্বরপুরী হরষিত ।
‘প্রভু’ হেন না জানেন, তবু বড় প্রীত ॥১০২॥','прабху декхи’ ш́рӣ-ӣш́вара-пурӣ хараш̣ита
‘прабху’ хӣнана̄ джа̄нера, табу бад̣а прӣта',NULL,NULL),('cb.adi.11.103','cb','cb.adi.11','ЧБ Ади 11.103',103,'হাসিয়া বোলেন,—“তুমি পরম-পণ্ডিত ।
আমি পুঁথি করিয়াছি কৃষ্ণের চরিত ॥১০৩॥','ха̄сийа̄ болена, — ‘туми парама-пан̣д̣ита
а̄ми пун̇тхи карийа̄чхи кр̣ш̣н̣ера чарита',NULL,NULL),('cb.adi.11.104','cb','cb.adi.11','ЧБ Ади 11.104',104,'সকল বলিবা,—কোথা থাকে কোন্ দোষ ? ।
ইহাতে আমার বড় পরম-সন্তোষ” ॥১০৪॥','сакала балиба̄, — котха̄ тха̄ке кон дош̣а?
иха̄те а̄ма̄ра бад̣а парама-сантош̣а’',NULL,NULL),('cb.adi.11.105','cb','cb.adi.11','ЧБ Ади 11.105',105,'প্রভু বোলে,—“ভক্ত-বাক্য কৃষ্ণের বর্ণন ।
ইহাতে যে দোষ দেখে, সে-ই ‘পাপী’ জন ॥১০৫॥','прабху боле — ‘бхакта-ва̄кйа кр̣ш̣н̣ера варн̣ана
иха̄те йе дош̣а декхе, се-и ‘па̄пӣ’ джана',NULL,NULL),('cb.adi.11.106','cb','cb.adi.11','ЧБ Ади 11.106',106,'ভক্তের কবিত্ব যে-তে-মতে কেনে নয় ।
সর্ব্বথা কৃষ্ণের প্রীতি তাহাতে নিশ্চয় ॥১০৬॥','сарватха̄ кр̣ш̣н̣ера прӣти та̄ха̄те ниш́чайа',NULL,NULL),('cb.adi.11.107','cb','cb.adi.11','ЧБ Ади 11.107',107,'মূর্খ বোলে ‘বিষ্ণায়’, ‘বিষ্ণবে’ বোলে ধীর ।
দুই বাক্য পরিগ্রহ করে কৃষ্ণ বীর ॥১০৭॥','мӯркха боле ‘виш̣н̣а̄йа’, ‘виш̣н̣аве’ боле дхӣра
дуи ва̄кйа париграха каре кр̣ш̣н̣а вӣра',NULL,NULL),('cb.adi.11.108','cb','cb.adi.11','ЧБ Ади 11.108',108,'মূর্খো বদতি বিষ্ণায় ধীরো বদতি বিষ্ণবে ।
উভয়োস্তু সমং পুণ্যং ভাবগ্রাহী জনার্দ্দনঃ ॥১০৮॥','мӯркхо вадати виш̣н̣а̄йа
дхӣро вадати виш̣н̣аве
убхайос ту самам̇ пун̣йам̇
бха̄ва-гра̄хӣ джана̄рданах̣',NULL,NULL),('cb.adi.11.109','cb','cb.adi.11','ЧБ Ади 11.109',109,'ইহাতে যে দোষ দেখে, তাহার সে দোষ ।
ভক্তের বর্ণনমাত্র কৃষ্ণের সন্তোষ ॥১০৯॥','иха̄те йе дош̣а декхе, та̄ха̄ра се дош̣а
бхактера варн̣ана-ма̄тра кр̣ш̣н̣ера сантош̣а',NULL,NULL),('cb.adi.11.110','cb','cb.adi.11','ЧБ Ади 11.110',110,'অতএব তোমার সে প্রেমের বর্ণন ।
ইহাতে দূষিবেক কোন্ সাহসিক জন ?” ॥১১০॥','атаева тома̄ра се премера варн̣ана
иха̄те дӯш̣ибека кон са̄хасика джана?’',NULL,NULL),('cb.adi.11.111','cb','cb.adi.11','ЧБ Ади 11.111',111,'শুনিয়া ঈশ্বরপুরী প্রভুর উত্তর ।
অমৃত-সিঞ্চিত হইল সর্ব্ব-কলেবর ॥১১১॥','ш́унийа̄ ӣш́вара-пурӣ прабхура уттара
амр̣та-син̃чита хаила сарва-калевара',NULL,NULL),('cb.adi.11.112','cb','cb.adi.11','ЧБ Ади 11.112',112,'পুনঃ হাসি’ বোলেন,—“তোমার দোষ নাই ।
অবশ্য বলিবা, দোষ থাকে যেই-ঠাঞি” ॥১১২॥','пунах̣ ха̄си’ болена, — ‘тома̄ра дош̣а на̄и
аваш́йа балиба̄, дош̣а тха̄ке йеи т̣ха̄н̃и’',NULL,NULL),('cb.adi.11.113','cb','cb.adi.11','ЧБ Ади 11.113',113,'এইমত প্রতিদিন প্রভু তান সঙ্গে ।
বিচার করেন দুই-চারি-দণ্ড রঙ্গে ॥১১৩॥
একদিন প্রভু তান কবিত্ব শুনিয়া ।
হাসি’ দূষিলেন,—“ধাতু না লাগে” বলিয়া ॥১১৪॥
প্রভু বোলে,—“এ ধাতু ‘আত্মনেপদী’ নয়” ।
বলিয়া চলিলা প্রভু আপন-আলয় ॥১১৫॥
ঈশ্বরপুরীও সর্ব্ব-শাস্ত্রেতে পণ্ডিত ।
বিদ্যারস-বিচারেও বড় হরষিত ॥১১৬॥
প্রভু গেলে সেই ‘ধাতু’ করেন বিচার ।
সিদ্ধান্ত করেন তঁহি অশেষপ্রকার ॥১১৭॥
সেই ‘ধাতু’ করেন ‘আত্মনেপদী’ নাম ।
আর-দিনে প্রভু গেলে, করেন ব্যাখ্যান ॥১১৮॥
“যে ধাতু ‘পরস্মৈপদী’ বলি’ গেলা তুমি ।
তাহা এই সাধিলুঁ ‘আত্মনেপদী’ আমি” ॥১১৯॥','эи-мата прати-дина прабху та̄’на сан̇ге
вича̄ра карена дуи са̄ри дан̣д̣а ран̇ге
эка-дина прабху та̄’на кавитва ш́унийа̄
ха̄си’ дӯш̣илена, ‘дха̄ту на̄ лаге’ балийа̄
прабху боле, — ‘е дха̄ту ‘а̄тманепадӣ’ найа’
балийа̄ чалила̄ прабху а̄пана-а̄лайа
ӣш́вара-пурӣ о сарва-ш́а̄стрете пан̣д̣ита
видйа̄-раса-вича̄ре о бад̣а хараш̣ита
